{
  "name": "starter-vue3-fullstack",
  "version": "1.0.0",
  "private": true,
  "workspaces": [
    "backend",
    "frontend"
  ],
  "scripts": {
    "dev": "concurrently -n backend,frontend -c blue,green \"npm run dev -w backend\" \"npm run dev -w frontend\"",
    "build": "npm run build -w backend && npm run build -w frontend",
    "migrate": "npm run migrate -w backend",
    "start": "npm run start -w backend",
    "test": "npm run test -w backend",
    "test:e2e": "PLAYWRIGHT_BROWSERS_PATH=.playwright playwright test",
    "check-env": "node -e \"const {execSync}=require('child_process');['git','node','npm'].forEach(cmd=>{try{execSync(cmd+' --version',{stdio:'ignore'})}catch(e){console.error('MISSING: '+cmd);process.exit(1)}})\""
  },
  "overrides": {
    "yaml": ">=2.8.3"
  },
  "devDependencies": {
    "@playwright/test": "^1.58.2",
    "concurrently": "^9.1.0",
    "vitest": "^4.1.4"
  }
}

